SELECT COUNT(DISTINCT S.PK_SIAPE) FROM CALC_HORA_AULA_MEDIA C JOIN SERVIDOR S ON S.PK_SIAPE = C.SIAPE WHERE C.ANO = 2023 AND C.SEMESTRE = 1 AND LOWER(C.SIGLA_CAMPUS) = LOWER('uru') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%educa%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%fisica%')